void ByteTrackNode::on_rect(
  const tier4_perception_msgs::msg::DetectedObjectsWithFeature::ConstSharedPtr msg)
{
  using Label = autoware_perception_msgs::msg::ObjectClassification;

  tier4_perception_msgs::msg::DetectedObjectsWithFeature out_objects;
  tier4_perception_msgs::msg::DynamicObjectArray out_objects_uuid;

  // Unpack detection results
  ObjectArray object_array;
  for (auto & feat_obj : msg->feature_objects) {
    Object obj;
    obj.x_offset = feat_obj.feature.roi.x_offset;
    obj.y_offset = feat_obj.feature.roi.y_offset;
    obj.height = feat_obj.feature.roi.height;
    obj.width = feat_obj.feature.roi.width;
    obj.score = feat_obj.object.existence_probability;
    obj.type = feat_obj.object.classification.front().label;
    object_array.emplace_back(obj);
  }

  autoware::bytetrack::ObjectArray objects = bytetrack_->update_tracker(object_array);
  for (const auto & tracked_object : objects) {
    tier4_perception_msgs::msg::DetectedObjectWithFeature object;
    // fit xy offset to 0 if roi is outside of image
    const int outside_x = std::max(-tracked_object.x_offset, 0);
    const int outside_y = std::max(-tracked_object.y_offset, 0);
    const int32_t output_x = std::max(tracked_object.x_offset, 0);
    const int32_t output_y = std::max(tracked_object.y_offset, 0);
    const int32_t output_width = tracked_object.width - outside_x;
    const int32_t output_height = tracked_object.height - outside_y;
    // convert int32 to uint32
    object.feature.roi.x_offset = static_cast<uint32_t>(output_x);
    object.feature.roi.y_offset = static_cast<uint32_t>(output_y);
    object.feature.roi.width = static_cast<uint32_t>(output_width);
    object.feature.roi.height = static_cast<uint32_t>(output_height);
    object.object.existence_probability = tracked_object.score;
    object.object.classification.emplace_back(
      autoware_perception_msgs::build<Label>().label(tracked_object.type).probability(1.0f));

    out_objects.feature_objects.push_back(object);

    auto tracked_uuid = tracked_object.unique_id;
    unique_identifier_msgs::msg::UUID uuid_msg;
    std::memcpy(uuid_msg.uuid.data(), &tracked_uuid, tracked_uuid.size());
    tier4_perception_msgs::msg::DynamicObject dynamic_obj;
    dynamic_obj.id = uuid_msg;
    out_objects_uuid.objects.push_back(dynamic_obj);
  }

  out_objects.header = msg->header;
  objects_pub_->publish(out_objects);

  out_objects_uuid.header = msg->header;
  objects_uuid_pub_->publish(out_objects_uuid);
}

ObjectArray ByteTrack::update_tracker(ObjectArray & input_objects)
{
  do_inference(input_objects);
  return latest_objects_;
}

bool ByteTrack::do_inference(ObjectArray & objects)
{
  // Re-format data
  std::vector<ByteTrackObject> bytetrack_objects;
  for (auto & obj : objects) {
    ByteTrackObject bytetrack_obj;
    bytetrack_obj.rect = cv::Rect(obj.x_offset, obj.y_offset, obj.width, obj.height);
    bytetrack_obj.prob = obj.score;
    bytetrack_obj.label = obj.type;
    bytetrack_objects.emplace_back(bytetrack_obj);
  }

  // cspell: ignore stracks tlwh
  // Update tracker
  std::vector<STrack> output_stracks = tracker_->update(bytetrack_objects);

  // Pack results
  latest_objects_.clear();
  for (const auto & tracking_result : output_stracks) {
    Object object{};
    std::vector<float> tlwh = tracking_result.tlwh;
    object.x_offset = tlwh[0];
    object.y_offset = tlwh[1];
    object.width = tlwh[2];
    object.height = tlwh[3];
    object.score = tracking_result.score;
    object.type = tracking_result.label;
    object.track_id = tracking_result.track_id;
    object.unique_id = tracking_result.unique_id;
    latest_objects_.emplace_back(object);
  }

  return true;
}

std::vector<STrack> ByteTracker::update(const std::vector<ByteTrackObject> & objects)
{
  ////////////////// Step 1: Get detections //////////////////
  this->frame_id++;
  std::vector<STrack> activated_stracks;
  std::vector<STrack> refind_stracks;
  std::vector<STrack> removed_stracks;
  std::vector<STrack> lost_stracks;
  std::vector<STrack> detections;
  std::vector<STrack> detections_low;

  std::vector<STrack> detections_cp;
  std::vector<STrack> tracked_stracks_swap;
  std::vector<STrack> resa, resb;
  std::vector<STrack> output_stracks;

  std::vector<STrack *> unconfirmed;
  std::vector<STrack *> tracked_stracks;
  std::vector<STrack *> strack_pool;
  std::vector<STrack *> r_tracked_stracks;

  if (objects.size() > 0) {
    for (size_t i = 0; i < objects.size(); i++) {
      std::vector<float> tlbr_;
      tlbr_.resize(4);
      tlbr_[0] = objects[i].rect.x;
      tlbr_[1] = objects[i].rect.y;
      tlbr_[2] = objects[i].rect.x + objects[i].rect.width;
      tlbr_[3] = objects[i].rect.y + objects[i].rect.height;

      float score = objects[i].prob;

      STrack strack(STrack::tlbr_to_tlwh(tlbr_), score, objects[i].label);
      if (score >= track_thresh) {
        detections.push_back(strack);
      } else {
        detections_low.push_back(strack);
      }
    }
  }

  // Add newly detected tracklets to tracked_stracks
  for (size_t i = 0; i < this->tracked_stracks.size(); i++) {
    if (!this->tracked_stracks[i].is_activated)
      unconfirmed.push_back(&this->tracked_stracks[i]);
    else
      tracked_stracks.push_back(&this->tracked_stracks[i]);
  }

  ////////////////// Step 2: First association, with IoU //////////////////
  strack_pool = joint_stracks(tracked_stracks, this->lost_stracks);
  // do prediction for each stracks
  for (size_t i = 0; i < strack_pool.size(); i++) {
    strack_pool[i]->predict(this->frame_id);
  }

  std::vector<std::vector<float> > dists;
  int dist_size = 0, dist_size_size = 0;
  dists = iou_distance(strack_pool, detections, dist_size, dist_size_size);

  std::vector<std::vector<int> > matches;
  std::vector<int> u_track, u_detection;
  linear_assignment(dists, dist_size, dist_size_size, match_thresh, matches, u_track, u_detection);

  for (size_t i = 0; i < matches.size(); i++) {
    STrack * track = strack_pool[matches[i][0]];
    STrack * det = &detections[matches[i][1]];
    if (track->state == TrackState::Tracked) {
      track->update(*det, this->frame_id, classification_decay_constant);
      activated_stracks.push_back(*track);
    } else {
      track->re_activate(*det, this->frame_id, false);
      refind_stracks.push_back(*track);
    }
  }

  ////////////////// Step 3: Second association, using low score dets //////////////////
  for (size_t i = 0; i < u_detection.size(); i++) {
    detections_cp.push_back(detections[u_detection[i]]);
  }
  detections.clear();
  detections.assign(detections_low.begin(), detections_low.end());

  for (size_t i = 0; i < u_track.size(); i++) {
    if (strack_pool[u_track[i]]->state == TrackState::Tracked) {
      r_tracked_stracks.push_back(strack_pool[u_track[i]]);
    }
  }

  dists.clear();
  dists = iou_distance(r_tracked_stracks, detections, dist_size, dist_size_size);

  matches.clear();
  u_track.clear();
  u_detection.clear();
  linear_assignment(dists, dist_size, dist_size_size, 0.5, matches, u_track, u_detection);

  for (size_t i = 0; i < matches.size(); i++) {
    STrack * track = r_tracked_stracks[matches[i][0]];
    STrack * det = &detections[matches[i][1]];
    if (track->state == TrackState::Tracked) {
      track->update(*det, this->frame_id, classification_decay_constant);
      activated_stracks.push_back(*track);
    } else {
      track->re_activate(*det, this->frame_id, false);
      refind_stracks.push_back(*track);
    }
  }

  for (size_t i = 0; i < u_track.size(); i++) {
    STrack * track = r_tracked_stracks[u_track[i]];
    if (track->state != TrackState::Lost) {
      track->mark_lost();
      lost_stracks.push_back(*track);
    }
  }

  // Deal with unconfirmed tracks, usually tracks with only one beginning frame
  detections.clear();
  detections.assign(detections_cp.begin(), detections_cp.end());

  dists.clear();
  dists = iou_distance(unconfirmed, detections, dist_size, dist_size_size);

  matches.clear();
  std::vector<int> u_unconfirmed;
  u_detection.clear();
  linear_assignment(dists, dist_size, dist_size_size, 0.7, matches, u_unconfirmed, u_detection);

  for (size_t i = 0; i < matches.size(); i++) {
    unconfirmed[matches[i][0]]->update(
      detections[matches[i][1]], this->frame_id, classification_decay_constant);
    activated_stracks.push_back(*unconfirmed[matches[i][0]]);
  }

  for (size_t i = 0; i < u_unconfirmed.size(); i++) {
    STrack * track = unconfirmed[u_unconfirmed[i]];
    track->mark_removed();
    removed_stracks.push_back(*track);
  }

  ////////////////// Step 4: Init new stracks //////////////////
  for (size_t i = 0; i < u_detection.size(); i++) {
    STrack * track = &detections[u_detection[i]];
    if (track->score < this->high_thresh) continue;
    track->activate(this->frame_id);
    activated_stracks.push_back(*track);
  }

  ////////////////// Step 5: Update state //////////////////
  for (size_t i = 0; i < this->lost_stracks.size(); i++) {
    if (this->frame_id - this->lost_stracks[i].end_frame() > this->max_time_lost) {
      this->lost_stracks[i].mark_removed();
      removed_stracks.push_back(this->lost_stracks[i]);
    }
  }

  for (size_t i = 0; i < this->tracked_stracks.size(); i++) {
    if (this->tracked_stracks[i].state == TrackState::Tracked) {
      tracked_stracks_swap.push_back(this->tracked_stracks[i]);
    }
  }
  this->tracked_stracks.clear();
  this->tracked_stracks.assign(tracked_stracks_swap.begin(), tracked_stracks_swap.end());

  this->tracked_stracks = joint_stracks(this->tracked_stracks, activated_stracks);
  this->tracked_stracks = joint_stracks(this->tracked_stracks, refind_stracks);

  this->lost_stracks = sub_stracks(this->lost_stracks, this->tracked_stracks);
  for (size_t i = 0; i < lost_stracks.size(); i++) {
    this->lost_stracks.push_back(lost_stracks[i]);
  }

  this->lost_stracks = sub_stracks(this->lost_stracks, this->removed_stracks);
  for (size_t i = 0; i < removed_stracks.size(); i++) {
    this->removed_stracks.push_back(removed_stracks[i]);
  }

  remove_duplicate_stracks(resa, resb, this->tracked_stracks, this->lost_stracks);

  this->tracked_stracks.clear();
  this->tracked_stracks.assign(resa.begin(), resa.end());
  this->lost_stracks.clear();
  this->lost_stracks.assign(resb.begin(), resb.end());

  for (size_t i = 0; i < this->tracked_stracks.size(); i++) {
    if (this->tracked_stracks[i].is_activated) {
      output_stracks.push_back(this->tracked_stracks[i]);
    }
  }
  return output_stracks;
}

std::vector<float> STrack::tlbr_to_tlwh(std::vector<float> & tlbr)
{
  tlbr[2] -= tlbr[0];
  tlbr[3] -= tlbr[1];
  return tlbr;
}

std::vector<STrack *> ByteTracker::joint_stracks(
  std::vector<STrack *> & tlista, std::vector<STrack> & tlistb)
{
  std::map<int, int> exists;
  std::vector<STrack *> res;
  for (size_t i = 0; i < tlista.size(); i++) {
    exists.insert(std::pair<int, int>(tlista[i]->track_id, 1));
    res.push_back(tlista[i]);
  }
  for (size_t i = 0; i < tlistb.size(); i++) {
    int tid = tlistb[i].track_id;
    if (!exists[tid] || exists.count(tid) == 0) {
      exists[tid] = 1;
      res.push_back(&tlistb[i]);
    }
  }
  return res;
}

void STrack::predict(const int frame_id)
{
  // check state is Tracked
  if (this->state != TrackState::Tracked) {
    // not tracked
    return;
  }

  // else do prediction
  float time_elapsed = _kf_parameters.dt * (frame_id - this->frame_id);
  // A matrix
  Eigen::MatrixXd A = Eigen::MatrixXd::Identity(_kf_parameters.dim_x, _kf_parameters.dim_x);
  A(IDX::X1, IDX::VX1) = time_elapsed;
  A(IDX::Y1, IDX::VY1) = time_elapsed;
  A(IDX::X2, IDX::VX2) = time_elapsed;
  A(IDX::Y2, IDX::VY2) = time_elapsed;

  // u and B matrix
  Eigen::MatrixXd u = Eigen::MatrixXd::Zero(_kf_parameters.dim_x, 1);
  Eigen::MatrixXd B = Eigen::MatrixXd::Zero(_kf_parameters.dim_x, _kf_parameters.dim_x);

  // get P_t
  Eigen::MatrixXd P_t = Eigen::MatrixXd::Zero(_kf_parameters.dim_x, _kf_parameters.dim_x);
  this->kalman_filter_.getP(P_t);

  // Q matrix
  Eigen::MatrixXd Q = Eigen::MatrixXd::Zero(_kf_parameters.dim_x, _kf_parameters.dim_x);
  Q(IDX::X1, IDX::X1) = _kf_parameters.q_cov_x;
  Q(IDX::Y1, IDX::Y1) = _kf_parameters.q_cov_y;
  Q(IDX::VX1, IDX::VX1) = _kf_parameters.q_cov_vx;
  Q(IDX::VY1, IDX::VY1) = _kf_parameters.q_cov_vy;
  Q(IDX::X2, IDX::X2) = _kf_parameters.q_cov_x;
  Q(IDX::Y2, IDX::Y2) = _kf_parameters.q_cov_y;
  Q(IDX::VX2, IDX::VX2) = _kf_parameters.q_cov_vx;
  Q(IDX::VY2, IDX::VY2) = _kf_parameters.q_cov_vy;

  // prediction
  if (!this->kalman_filter_.predict(u, A, B, Q)) {
    std::cerr << "Cannot predict" << std::endl;
  }
}

std::vector<std::vector<float>> ByteTracker::iou_distance(
  std::vector<STrack *> & atracks, std::vector<STrack> & btracks, int & dist_size,
  int & dist_size_size)
{
  std::vector<std::vector<float>> cost_matrix;
  if (atracks.size() * btracks.size() == 0) {
    dist_size = atracks.size();
    dist_size_size = btracks.size();
    return cost_matrix;
  }
  std::vector<std::vector<float>> atlbrs, btlbrs;
  for (size_t i = 0; i < atracks.size(); i++) {
    atlbrs.push_back(atracks[i]->tlbr);
  }
  for (size_t i = 0; i < btracks.size(); i++) {
    btlbrs.push_back(btracks[i].tlbr);
  }

  dist_size = atracks.size();
  dist_size_size = btracks.size();

  std::vector<std::vector<float>> _ious = ious(atlbrs, btlbrs);

  for (size_t i = 0; i < _ious.size(); i++) {
    std::vector<float> _iou;
    for (size_t j = 0; j < _ious[i].size(); j++) {
      _iou.push_back(1 - _ious[i][j]);
    }
    cost_matrix.push_back(_iou);
  }

  return cost_matrix;
}

std::vector<std::vector<float>> ByteTracker::ious(
  std::vector<std::vector<float>> & atlbrs, std::vector<std::vector<float>> & btlbrs)
{
  std::vector<std::vector<float>> ious;
  if (atlbrs.size() * btlbrs.size() == 0) return ious;

  ious.resize(atlbrs.size());
  for (size_t i = 0; i < ious.size(); i++) {
    ious[i].resize(btlbrs.size());
  }

  // bbox_ious
  for (size_t k = 0; k < btlbrs.size(); k++) {
    float box_area = (btlbrs[k][2] - btlbrs[k][0] + 1) * (btlbrs[k][3] - btlbrs[k][1] + 1);
    for (size_t n = 0; n < atlbrs.size(); n++) {
      float iw = std::min(atlbrs[n][2], btlbrs[k][2]) - std::max(atlbrs[n][0], btlbrs[k][0]) + 1;
      if (iw > 0) {
        float ih = std::min(atlbrs[n][3], btlbrs[k][3]) - std::max(atlbrs[n][1], btlbrs[k][1]) + 1;
        if (ih > 0) {
          float ua = (atlbrs[n][2] - atlbrs[n][0] + 1) * (atlbrs[n][3] - atlbrs[n][1] + 1) +
                     box_area - iw * ih;
          ious[n][k] = iw * ih / ua;
        } else {
          ious[n][k] = 0.0;
        }
      } else {
        ious[n][k] = 0.0;
      }
    }
  }

  return ious;
}

void ByteTracker::linear_assignment(
  std::vector<std::vector<float>> & cost_matrix, int cost_matrix_size, int cost_matrix_size_size,
  float thresh, std::vector<std::vector<int>> & matches, std::vector<int> & unmatched_a,
  std::vector<int> & unmatched_b)
{
  if (cost_matrix.size() == 0) {
    for (int i = 0; i < cost_matrix_size; i++) {
      unmatched_a.push_back(i);
    }
    for (int i = 0; i < cost_matrix_size_size; i++) {
      unmatched_b.push_back(i);
    }
    return;
  }

  std::vector<int> rowsol;
  std::vector<int> colsol;
  [[maybe_unused]] float c = lapjv(cost_matrix, rowsol, colsol, true, thresh);
  for (size_t i = 0; i < rowsol.size(); i++) {
    if (rowsol[i] >= 0) {
      std::vector<int> match;
      match.push_back(i);
      match.push_back(rowsol[i]);
      matches.push_back(match);
    } else {
      unmatched_a.push_back(i);
    }
  }

  for (size_t i = 0; i < colsol.size(); i++) {
    if (colsol[i] < 0) {
      unmatched_b.push_back(i);
    }
  }
}

double ByteTracker::lapjv(
  const std::vector<std::vector<float>> & cost, std::vector<int> & rowsol,
  std::vector<int> & colsol, bool extend_cost, float cost_limit, bool return_cost)
{
  std::vector<std::vector<float>> cost_c;
  cost_c.assign(cost.begin(), cost.end());

  int n_rows = cost.size();
  int n_cols = cost[0].size();
  rowsol.resize(n_rows);
  colsol.resize(n_cols);

  int n = 0;
  if (n_rows == n_cols) {
    n = n_rows;
  } else {
    if (!extend_cost) {
      std::cout << "set extend_cost=True" << std::endl;
      // system("pause");
      exit(0);
    }
  }

  if (extend_cost || cost_limit < std::numeric_limits<float>::max()) {
    std::vector<std::vector<float>> cost_c_extended;

    n = n_rows + n_cols;
    cost_c_extended.resize(n);
    for (size_t i = 0; i < cost_c_extended.size(); i++) cost_c_extended[i].resize(n);

    if (cost_limit < std::numeric_limits<float>::max()) {
      for (size_t i = 0; i < cost_c_extended.size(); i++) {
        for (size_t j = 0; j < cost_c_extended[i].size(); j++) {
          cost_c_extended[i][j] = cost_limit / 2.0;
        }
      }
    } else {
      float cost_max = -1;
      for (size_t i = 0; i < cost_c.size(); i++) {
        for (size_t j = 0; j < cost_c[i].size(); j++) {
          if (cost_c[i][j] > cost_max) cost_max = cost_c[i][j];
        }
      }
      for (size_t i = 0; i < cost_c_extended.size(); i++) {
        for (size_t j = 0; j < cost_c_extended[i].size(); j++) {
          cost_c_extended[i][j] = cost_max + 1;
        }
      }
    }

    for (size_t i = n_rows; i < cost_c_extended.size(); i++) {
      for (size_t j = n_cols; j < cost_c_extended[i].size(); j++) {
        cost_c_extended[i][j] = 0;
      }
    }
    for (int i = 0; i < n_rows; i++) {
      for (int j = 0; j < n_cols; j++) {
        cost_c_extended[i][j] = cost_c[i][j];
      }
    }

    cost_c.clear();
    cost_c.assign(cost_c_extended.begin(), cost_c_extended.end());
  }

  double ** cost_ptr;
  cost_ptr = new double *[sizeof(double *) * n];
  for (int i = 0; i < n; i++) cost_ptr[i] = new double[sizeof(double) * n];

  for (int i = 0; i < n; i++) {
    for (int j = 0; j < n; j++) {
      cost_ptr[i][j] = cost_c[i][j];
    }
  }

  int * x_c = new int[sizeof(int) * n];
  int * y_c = new int[sizeof(int) * n];

  int ret = lapjv_internal(n, cost_ptr, x_c, y_c);
  if (ret != 0) {
    std::cout << "Calculate Wrong!" << std::endl;
    // system("pause");
    exit(0);
  }

  double opt = 0.0;

  if (n != n_rows) {
    for (int i = 0; i < n; i++) {
      if (x_c[i] >= n_cols) x_c[i] = -1;
      if (y_c[i] >= n_rows) y_c[i] = -1;
    }
    for (int i = 0; i < n_rows; i++) {
      rowsol[i] = x_c[i];
    }
    for (int i = 0; i < n_cols; i++) {
      colsol[i] = y_c[i];
    }

    if (return_cost) {
      for (size_t i = 0; i < rowsol.size(); i++) {
        if (rowsol[i] != -1) {
          opt += cost_ptr[i][rowsol[i]];
        }
      }
    }
  } else if (return_cost) {
    for (size_t i = 0; i < rowsol.size(); i++) {
      opt += cost_ptr[i][rowsol[i]];
    }
  }

  for (int i = 0; i < n; i++) {
    delete[] cost_ptr[i];
  }
  delete[] cost_ptr;
  delete[] x_c;
  delete[] y_c;

  return opt;
}

int lapjv_internal(const uint_t n, cost_t * cost[], int_t * x, int_t * y)
{
  int ret;
  int_t * free_rows;
  cost_t * v;

  NEW(free_rows, int_t, n);
  NEW(v, cost_t, n);
  ret = ccrrt_dense(n, cost, free_rows, x, y, v);
  int i = 0;
  while (ret > 0 && i < 2) {
    ret = carr_dense(n, cost, ret, free_rows, x, y, v);
    i++;
  }
  if (ret > 0) {
    ret = ca_dense(n, cost, ret, free_rows, x, y, v);
  }
  FREE(v);
  FREE(free_rows);
  return ret;
}

int_t ccrrt_dense(
  const uint_t n, cost_t * cost[], int_t * free_rows, int_t * x, int_t * y, cost_t * v)
{
  int_t n_free_rows;
  boolean * unique;

  for (uint_t i = 0; i < n; i++) {
    x[i] = -1;
    v[i] = LARGE;
    y[i] = 0;
  }
  for (uint_t i = 0; i < n; i++) {
    for (uint_t j = 0; j < n; j++) {
      const cost_t c = cost[i][j];
      if (c < v[j]) {
        v[j] = c;
        y[j] = i;
      }
      PRINTF("i=%d, j=%d, c[i,j]=%f, v[j]=%f y[j]=%d\n", i, j, c, v[j], y[j]);
    }
  }
  PRINT_COST_ARRAY(v, n);
  PRINT_INDEX_ARRAY(y, n);
  NEW(unique, boolean, n);
  memset(unique, TRUE, n);
  {
    int_t j = n;
    do {
      j--;
      const int_t i = y[j];
      if (x[i] < 0) {
        x[i] = j;
      } else {
        unique[i] = FALSE;
        y[j] = -1;
      }
    } while (j > 0);
  }
  n_free_rows = 0;
  for (uint_t i = 0; i < n; i++) {
    if (x[i] < 0) {
      free_rows[n_free_rows++] = i;
    } else if (unique[i]) {
      const int_t j = x[i];
      cost_t min = LARGE;
      for (uint_t j2 = 0; j2 < n; j2++) {
        if (j2 == (uint_t)j) {
          continue;
        }
        const cost_t c = cost[i][j2] - v[j2];
        if (c < min) {
          min = c;
        }
      }
      PRINTF("v[%d] = %f - %f\n", j, v[j], min);
      v[j] -= min;
    }
  }
  FREE(unique);
  return n_free_rows;
}

int_t carr_dense(
  const uint_t n, cost_t * cost[], const uint_t n_free_rows, int_t * free_rows, int_t * x,
  int_t * y, cost_t * v)
{
  uint_t current = 0;
  int_t new_free_rows = 0;
  uint_t rr_cnt = 0;
  PRINT_INDEX_ARRAY(x, n);
  PRINT_INDEX_ARRAY(y, n);
  PRINT_COST_ARRAY(v, n);
  PRINT_INDEX_ARRAY(free_rows, n_free_rows);
  while (current < n_free_rows) {
    int_t i0;
    int_t j1, j2;
    cost_t v1, v2, v1_new;
    boolean v1_lowers;

    rr_cnt++;
    PRINTF("current = %d rr_cnt = %d\n", current, rr_cnt);
    const int_t free_i = free_rows[current++];
    j1 = 0;
    v1 = cost[free_i][0] - v[0];
    j2 = -1;
    v2 = LARGE;
    for (uint_t j = 1; j < n; j++) {
      PRINTF("%d = %f %d = %f\n", j1, v1, j2, v2);
      const cost_t c = cost[free_i][j] - v[j];
      if (c < v2) {
        if (c >= v1) {
          v2 = c;
          j2 = j;
        } else {
          v2 = v1;
          v1 = c;
          j2 = j1;
          j1 = j;
        }
      }
    }
    i0 = y[j1];
    v1_new = v[j1] - (v2 - v1);
    v1_lowers = v1_new < v[j1];
    PRINTF(
      "%d %d 1=%d,%f 2=%d,%f v1'=%f(%d,%g) \n", free_i, i0, j1, v1, j2, v2, v1_new, v1_lowers,
      v[j1] - v1_new);
    if (rr_cnt < current * n) {
      if (v1_lowers) {
        v[j1] = v1_new;
      } else if (i0 >= 0 && j2 >= 0) {
        j1 = j2;
        i0 = y[j2];
      }
      if (i0 >= 0) {
        if (v1_lowers) {
          free_rows[--current] = i0;
        } else {
          free_rows[new_free_rows++] = i0;
        }
      }
    } else {
      PRINTF("rr_cnt=%d >= %d (current=%d * n=%d)\n", rr_cnt, current * n, current, n);
      if (i0 >= 0) {
        free_rows[new_free_rows++] = i0;
      }
    }
    x[free_i] = j1;
    y[j1] = free_i;
  }
  return new_free_rows;
}

int_t ca_dense(
  const uint_t n, cost_t * cost[], const uint_t n_free_rows, int_t * free_rows, int_t * x,
  int_t * y, cost_t * v)
{
  int_t * pred;

  NEW(pred, int_t, n);

  for (int_t * pfree_i = free_rows; pfree_i < free_rows + n_free_rows; pfree_i++) {
    int_t i = -1, j;
    uint_t k = 0;

    PRINTF("looking at free_i=%d\n", *pfree_i);
    j = find_path_dense(n, cost, *pfree_i, y, v, pred);
    ASSERT(j >= 0);
    ASSERT(j < n);
    while (i != *pfree_i) {
      PRINTF("augment %d\n", j);
      PRINT_INDEX_ARRAY(pred, n);
      i = pred[j];
      PRINTF("y[%d]=%d -> %d\n", j, y[j], i);
      y[j] = i;
      PRINT_INDEX_ARRAY(x, n);
      SWAP_INDICES(j, x[i]);
      k++;
      if (k >= n) {
        ASSERT(FALSE);
      }
    }
  }
  FREE(pred);
  return 0;
}

int_t find_path_dense(
  const uint_t n, cost_t * cost[], const int_t start_i, int_t * y, cost_t * v, int_t * pred)
{
  uint_t lo = 0, hi = 0;
  int_t final_j = -1;
  uint_t n_ready = 0;
  int_t * cols;
  cost_t * d;

  NEW(cols, int_t, n);
  NEW(d, cost_t, n);

  for (uint_t i = 0; i < n; i++) {
    cols[i] = i;
    pred[i] = start_i;
    d[i] = cost[start_i][i] - v[i];
  }
  PRINT_COST_ARRAY(d, n);
  while (final_j == -1) {
    // No columns left on the SCAN list.
    if (lo == hi) {
      PRINTF("%d..%d -> find\n", lo, hi);
      n_ready = lo;
      hi = find_dense(n, lo, d, cols, y);
      PRINTF("check %d..%d\n", lo, hi);
      PRINT_INDEX_ARRAY(cols, n);
      for (uint_t k = lo; k < hi; k++) {
        const int_t j = cols[k];
        if (y[j] < 0) {
          final_j = j;
        }
      }
    }
    if (final_j == -1) {
      PRINTF("%d..%d -> scan\n", lo, hi);
      final_j = scan_dense(n, cost, &lo, &hi, d, cols, pred, y, v);
      PRINT_COST_ARRAY(d, n);
      PRINT_INDEX_ARRAY(cols, n);
      PRINT_INDEX_ARRAY(pred, n);
    }
  }

  PRINTF("found final_j=%d\n", final_j);
  PRINT_INDEX_ARRAY(cols, n);
  {
    const cost_t mind = d[cols[lo]];
    for (uint_t k = 0; k < n_ready; k++) {
      const int_t j = cols[k];
      v[j] += d[j] - mind;
    }
  }

  FREE(cols);
  FREE(d);

  return final_j;
}

uint_t find_dense(
  const uint_t n, uint_t lo, const cost_t * d, int_t * cols, [[maybe_unused]] int_t * y)
{
  uint_t hi = lo + 1;
  cost_t mind = d[cols[lo]];
  for (uint_t k = hi; k < n; k++) {
    int_t j = cols[k];
    if (d[j] <= mind) {
      if (d[j] < mind) {
        hi = lo;
        mind = d[j];
      }
      cols[k] = cols[hi];
      cols[hi++] = j;
    }
  }
  return hi;
}

int_t scan_dense(
  const uint_t n, cost_t * cost[], uint_t * plo, uint_t * phi, cost_t * d, int_t * cols,
  int_t * pred, const int_t * y, const cost_t * v)
{
  uint_t lo = *plo;
  uint_t hi = *phi;
  cost_t h, cred_ij;

  while (lo != hi) {
    int_t j = cols[lo++];
    const int_t i = y[j];
    const cost_t mind = d[j];
    h = cost[i][j] - v[j] - mind;
    PRINTF("i=%d j=%d h=%f\n", i, j, h);
    // For all columns in TODO
    for (uint_t k = hi; k < n; k++) {
      j = cols[k];
      cred_ij = cost[i][j] - v[j] - h;
      if (cred_ij < d[j]) {
        d[j] = cred_ij;
        pred[j] = i;
        if (cred_ij == mind) {
          if (y[j] < 0) {
            return j;
          }
          cols[k] = cols[hi];
          cols[hi++] = j;
        }
      }
    }
  }
  *plo = lo;
  *phi = hi;
  return -1;
}

publish(const T & msg)
{
  // Avoid allocating when not using intra process.
  if (!intra_process_is_enabled_) {
    // In this case we're not using intra process.
    return this->do_inter_process_publish(msg);
  }
  // Otherwise we have to allocate memory in a unique_ptr and pass it along.
  // As the message is not const, a copy should be made.
  // A shared_ptr<const MessageT> could also be constructed here.
  auto unique_msg = this->duplicate_ros_message_as_unique_ptr(msg);
  this->publish(std::move(unique_msg));
}
